/**
 * 전력생산 데이터를 조회한다.
 */
scwin.searchEpwrPrdctn = function() {
	var dashYear = dmaDashYear.getJSON();
	var strtDt = dashYear.dashYearSelected + "01";
	var endDt = dashYear.dashYearSelected + utilLib.getCurrentDate("MM");
	if (dashYear.dashYearSelected != utilLib.getCurrentDate("yyyy")) {
		endDt = dashYear.dashYearSelected + "12";
	}
	var dashBasin = dmaDashBasin.getJSON();
	var basin = dashBasin.dashBasinSelected;

	basin = scwin.initData.dashBasinCode[scwin.initData.dashBasinValue[basin]] || "ALL";

	var queryString = `?strtDt=${strtDt}`;
	queryString += `&endDt=${endDt}`;
	queryString += `&ecsBasinDivCd=${basin}`;

	var option = {
		action : "/ec/pc/retrieve-prdctn-epwr.do" +
			queryString,
		method : "get",
		resData : dltEpwrPrdctnData,
		success : "scwin.searchEpwrPrdctnCallBack",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

