	// 우측 물방울 라벨(연간소비량) 데이터를 설정한다.
	//spnWaterDropFyerCnstqy.setLabel(ecsLib.dsplFrmt((epwrCnstnData.find(obj => obj.inqireDe == "fyer" && obj.iemDivId == "cnstnTotal") || 0).inqireIemVu));
	spnWaterDropFyerCnstqy.setLabel(ecsLib.dsplFrmt((epwrCnstnData.find(obj => obj.inqireDe == dashYear && obj.iemDivId == "cnstnTotal") || 0).inqireIemVu, 2));
	// 우측 물방울 라벨(연간소비정산) 데이터를 설정한다.
	//spnWaterDropFyerCnstnExcclc.setLabel(ecsLib.dsplFrmt((epwrCnstnData.find(obj => obj.inqireDe == "fyer" && obj.iemDivId == "cnstnExcclcTotal") || 0).inqireIemVu));
	spnWaterDropFyerCnstnExcclc.setLabel(ecsLib.dsplFrmt((epwrCnstnData.find(obj => obj.inqireDe == dashYear && obj.iemDivId == "cnstnExcclcTotal") || 0).inqireIemVu, 2));
};

