/**
* 전력에너지 운영현황 차트 설정
 * @param id : 차트 그룹 ID
 */
scwin.chartReadyHandlerEpwrEnergy = function(id) {
	var elctrnEngData = dltEpwrEnergyData.getAllJSON();
	var chartList = [];

	var minMonth = String(elctrnEngData.reduce((minObj, obj) => Number(minObj.inqireDe) > Number(obj.inqireDe) ? obj : minObj).inqireDe);
	/*
	var minMonth = String(elctrnEngData.reduce((min, obj) => {
		if (!min && (min > Number(obj.inqireDe))) {
			return Number(obj.inqireDe);
		} else {
			return min;
		}
	}, null));
	*/
	var maxMonth = String(elctrnEngData.reduce((max, obj) => Math.max(max, Number(obj.inqireDe)), 0));
	var diffYear = minMonth.substr(0, 4) != maxMonth.substr(0, 4) ? true : false;
	elctrnEngData.forEach(data => {
		var findObj = chartList.find(obj => obj.month == data.inqireDe);
		if (findObj) {
			findObj[data.iemDivId] = data.inqireIemVu;
		} else {
			var tempObj = { "month" : data.inqireDe };
			if (data.iemDivId) {
				if (data.inqireIemVu) {
					tempObj[data.iemDivId] = data.inqireIemVu;
				} else {
					//tempObj[data.iemDivId] = 0;
				}
			}
			chartList.push(tempObj);
		}
	});
	chartList.map(obj => obj.cmpr = (obj.prdctn - obj.cnstn) ? obj.prdctn - obj.cnstn : 0);
	var maxPData = chartList.reduce((max, obj) => obj.prdctn ? Math.max(max, Number(obj.prdctn)) : max, 0);
	var maxCData = chartList.reduce((max, obj) => {
		if (obj.cnstn) {
			if (Number(obj.cnstn) < 0) {
				return Math.max(max, Number(obj.cnstn) * -1);
			} else {
				return Math.max(max, Number(obj.cnstn));
			}
		} else {
			return max;
		}
	}, 0);
	var maxLeftData = Math.max(maxPData, maxCData);
	var leftInterval = Math.ceil((maxLeftData / scwin.initData.chart.elctrnEngIntervalCount * 1.1) / scwin.initData.chart.elctrnEngUnit) * scwin.initData.chart.elctrnEngUnit;
	chartList.flatMap(obj => {
		if (Number(obj.cnstn) > 0) {
			obj.cnstn = Number(obj.cnstn) * -1;
		}
	});
	var leftMaximumData = leftInterval * scwin.initData.chart.elctrnEngIntervalCount;
	var leftMinimumData = leftMaximumData * -1;
	var maxRightData = chartList.reduce((max, obj) => obj.cmpr ? Math.max(max, Number(obj.cmpr) < 0 ? Number(obj.cmpr) * -1 : Number(obj.cmpr)) : max, 0);
	var rightInterval = Math.ceil((maxRightData / scwin.initData.chart.elctrnEngIntervalCount * 1.1) / scwin.initData.chart.elctrnEngUnit) * scwin.initData.chart.elctrnEngUnit;
	var rightMaximumData = rightInterval * scwin.initData.chart.elctrnEngIntervalCount;
	var rightMinimumData = rightMaximumData * -1;

	var layoutStr = '<rMateChart backgroundColor="" cornerRadius="12">'
		+ '	<Options>'
		+ '		<Legend position="center" vAlign="top" hAlign="right" verticalGap="2" fontWeight="bold" border="0" background="transparent" />'
		+ '	</Options>'
		+ '	<Combination2DChart showDataTips="true" columnWidthRatinqireDe="0.65" dataTipDisplayMode="axis" type="stacked">'
		+ '		<horizontalAxis>'
		+ '			<CategoryAxis id="hAxis" categoryField="month" labelJsFunction="' + $p.id + 'scwin.elctrnEngCategoryLabelHandler" />'
		+ '		</horizontalAxis>'
		+ '		<horizontalAxisRenderers>'
		+ '			<Axis2DRenderer axis="{hAxis}" visible="true" textAlign="right" canDropLabels="false" />'
		+ '		</horizontalAxisRenderers>'
		+ '		<verticalAxis>'
		+ '			<LinearAxis id="vAxisL" interval="' + leftInterval + '" baseAtZero="false" maximum="' + leftMaximumData + '" minimum="' + leftMinimumData + '" title="MWh" />'
		+ '		</verticalAxis>'
		+ '		<verticalAxisRenderers>'
		+ '			<Axis2DRenderer axis="{vAxisL}" visible="true" placement="left" verticalAxisTitleAlignment="vertical" titleGap="0" canDropLabels="false" showLine="false" labelJsFunction="' + $p.id + 'scwin.elctrnEngLeftLinearLabelHandler" />'
		+ '			<Axis2DRenderer axis="{vAxisR}" visible="true" placement="right" verticalAxisTitleAlignment="top" titleGap="0" canDropLabels="false" showLine="false" labelJsFunction="' + $p.id + 'scwin.elctrnEngRightLinearLabelHandler" />'
		+ '		</verticalAxisRenderers>'
		+ '		<series>'
		+ '			<Column2DSet type="stacked">'
		+ '				<series>'
		+ '					<Column2DSeries color="#222222" font-weight="bold" yField="prdctn" displayName="생산량" fillJsFunction="' + $p.id + 'scwin.elctrnEngPrdctnFillHandler">'
		+ '						<fill>'
		+ '							<SolidColor color="#F8C597" />'
		+ '						</fill>'
		+ '						<showDataEffect>'
		+ '							<SeriesInterpolate />'
		+ '						</showDataEffect>'
		+ '					</Column2DSeries>'
		+ '					<Column2DSeries color="#222222" font-weight="bold" yField="cnstn" displayName="소비량" fillJsFunction="' + $p.id + 'scwin.elctrnEngCnstnFillHandler">'
		+ '						<fill>'
		+ '							<SolidColor color="#8ECEF2" />'
		+ '						</fill>'
		+ '						<showDataEffect>'
		+ '							<SeriesInterpolate />'
		+ '						</showDataEffect>'
		+ '					</Column2DSeries>'
		+ '				</series>'
		+ '			</Column2DSet>'
		+ '			<Line2DSeries radius="5" color="#222222" font-weight="bold" yField="cmpr" displayName="차이" itemRenderer="CircleItemRenderer">'
		+ '				<verticalAxis>'
		+ '					<LinearAxis id="vAxisR" interval="' + rightInterval + '" baseAtZero="false" maximum="' + rightMaximumData + '" minimum="' + rightMinimumData + '" />'
		+ '				</verticalAxis>'
		+ '				<lineStroke>'
		+ '					<Stroke color="#83DCCE" weight="3"/>'
		+ '				</lineStroke>'
		+ '				<stroke>'
		+ '					<Stroke color="#219D9D" weight="2"/>'
		+ '				</stroke>'
		+ '				<showDataEffect>'
		+ '					<SeriesInterpolate />'
		+ '				</showDataEffect>'
		+ '			</Line2DSeries>'
		+ '		</series>';
	if (diffYear) {
		layoutStr += '<backgroundElements>'
			+ '			<GridLines/>'
			+ '			<AxisMarker>'
			+ '				<ranges>'
			+ '					<AxisRange startValue="' + minMonth + '" endValue="' + minMonth.substr(0, 4) + '12" startRangePosition="left" endRangePosition="right" horizontal="false">'
			+ '						<fill>'
			+ '							<SolidColor color="#CCCCCC" alpha="0.3"/>'
			+ '						</fill>'
			+ '					</AxisRange>'
			+ '				</ranges>'
			+ '			</AxisMarker>'
			+ '		</backgroundElements>';
	}
	layoutStr += '	</Combination2DChart>'
		+ '</rMateChart>';

	document.getElementById(id).setLayout(layoutStr);
	document.getElementById(id).setData(chartList);
};

/**
 * 유역별 생산현황 차트 데이터를 조회한다.
 */
scwin.searchChartPrdctnData = function() {
	var dashYear = dmaDashYear.getJSON();
	var strtDt = dashYear.dashYearSelected + "01";
	var endDt = dashYear.dashYearSelected + utilLib.getCurrentDate("MM");
	if (dashYear.dashYearSelected != utilLib.getCurrentDate("yyyy")) {
		endDt = dashYear.dashYearSelected + "12";
	}
	var dashBasin = dmaDashBasin.getJSON();
	var basin = dashBasin.dashBasinSelected;

	basin = scwin.initData.dashBasinCode[scwin.initData.dashBasinValue[basin]] || "ALL";

	var queryString = `?strtDt=${strtDt}`;
	queryString += `&endDt=${endDt}`;
	queryString += `&ecsBasinDivCd=${basin}`;

	var option = {
		action : "ec/pc/retrieve-prdctn.do" +
			queryString,
		method : "get",
		resData : dltPrdctnData,
		success : "scwin.searchChartPrdctnDataCallBack",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

