};

/**
* 유역별 생산현황 차트 설정
 * @param id : 차트 그룹 ID
 */
scwin.chartReadyHandlerPrdctn = function(id) {
	var dashYear = Number(dmaDashYear.getJSON().dashYearSelected);
	var prdctnData = dltPrdctnData.getAllJSON();
	var dashBasin = dmaDashBasin.getJSON();
	var basin = dashBasin.dashBasinSelected;
	var chartList = [];

	if (basin == "전체") {
		Object.keys(scwin.initData.chart.prdctnLabel).forEach(source => {
			var temp = prdctnData.filter(obj => obj.hqNm.startsWith(scwin.initData.chart.prdctnLabel[source]));
			if (scwin.initData.chart.prdctnLabel[source] == "영섬유역") temp = prdctnData.filter(obj => obj.hqNm.endsWith(scwin.initData.chart.prdctnLabel[source].substr(1)));
			// 유역, 대수력, 소수력, 조력, 태양광, 풍력, 수열
			chartList.push({
				"basin" : scwin.initData.chart.prdctnLabel[source],
				"prdctnLgwtpw" : (temp[temp.findIndex(obj => Number(obj.inqireDe) == dashYear && obj.elcpwstnClsNm.endsWith("대수력"))] || 0).inqireIemVu,
				"prdctnSmlhp" : (temp.reduce((sum, obj) => Number(obj.inqireDe) == dashYear && obj.elcpwstnClsNm == "보소수력" || Number(obj.inqireDe) == dashYear && obj.elcpwstnClsNm == "소수력" ? sum + Number(obj.inqireIemVu) : sum, 0) || 0),
				"prdctnTdpw" : (temp[temp.findIndex(obj => Number(obj.inqireDe) == dashYear && obj.elcpwstnClsNm.endsWith("조력"))] || 0).inqireIemVu,
				"prdctnSnpw" : (temp[temp.findIndex(obj => Number(obj.inqireDe) == dashYear && obj.elcpwstnClsNm.endsWith("태양광"))] || 0).inqireIemVu,
				"prdctnWdpw" : (temp[temp.findIndex(obj => Number(obj.inqireDe) == dashYear && obj.elcpwstnClsNm.endsWith("풍력"))] || 0).inqireIemVu,
				"prdctnWtht" : (temp[temp.findIndex(obj => Number(obj.inqireDe) == dashYear && obj.elcpwstnClsNm.endsWith("수열"))] || 0).inqireIemVu
			});
		});
		var maxData = chartList.reduce((max, obj) => Math.max(max, Object.values(obj).reduce((sum, innerObj) => {
			if (Number(innerObj)) {
				sum += innerObj;
			}
			return sum;
		}, 0)), 0);
		var interval = Math.ceil((maxData / scwin.initData.chart.prdctnIntervalCount) / scwin.initData.chart.prdctnUnit) * scwin.initData.chart.prdctnUnit;

		var layoutStr = '<rMateChart backgroundColor="" cornerRadius="12">'
			+ '	<Options>'
			+ '		<Legend position="center" vAlign="top" hAlign="right" verticalGap="2" fontWeight="bold" border="0" background="transparent" />'
			+ '	</Options>'
			+ '	<NumberFormatter id="numFmt" useThousandsSeparator="true" precision="2"/>'
			+ '	<Column2DChart showDataTips="true" columnWidthRatio="0.45" dataTipDisplayMode="axis">'
			+ '		<horizontalAxis>'
			+ '			<CategoryAxis id="hAxis" categoryField="basin" />'
			+ '		</horizontalAxis>'
			+ '		<horizontalAxisRenderers>'
			+ '			<Axis2DRenderer axis="{hAxis}" visible="true" textAlign="right" canDropLabels="false" />'
			+ '		</horizontalAxisRenderers>'
			+ '		<verticalAxis>'
			+ '			<LinearAxis id="vAxis" interval="' + interval + '" title="MWh"/>'
			+ '		</verticalAxis>'
			+ '		<verticalAxisRenderers>'
			+ '			<Axis2DRenderer axis="{vAxis}" visible="true" placement="left" verticalAxisTitleAlignment="vertical" titleGap="0" canDropLabels="false" showLine="false" />'
			+ '		</verticalAxisRenderers>'
			+ '		<series>'
			+ '			<Column2DSet type="stacked" showTotalLabel="true" totalLabelJsFunction="'+ $p.id + 'scwin.prdctnTotalLabelHandler">'
			+ '				<series>'
			+ '					<Column2DSeries color="#222222" font-weight="bold" yField="prdctnLgwtpw" displayName="대수력" formatter="{numFmt}">'
			+ '						<fill>'
			+ '							<SolidColor color="#7DD2FF" />'
			+ '						</fill>'
			+ '						<showDataEffect>'
			+ '							<SeriesInterpolate />'
			+ '						</showDataEffect>'
			+ '					</Column2DSeries>'
			+ '					<Column2DSeries color="#222222" font-weight="bold" yField="prdctnSmlhp" displayName="소수력" formatter="{numFmt}">'
			+ '						<fill>'
			+ '							<SolidColor color="#FFA0A7" />'
			+ '						</fill>'
			+ '						<showDataEffect>'
			+ '							<SeriesInterpolate />'
			+ '						</showDataEffect>'
			+ '					</Column2DSeries>'
			+ '					<Column2DSeries color="#222222" font-weight="bold" yField="prdctnTdpw" displayName="조력" formatter="{numFmt}">'
			+ '						<fill>'
			+ '							<SolidColor color="#D1D1D1" />'
			+ '						</fill>'
			+ '						<showDataEffect>'
			+ '							<SeriesInterpolate />'
			+ '						</showDataEffect>'
			+ '					</Column2DSeries>'
			+ '					<Column2DSeries color="#222222" font-weight="bold" yField="prdctnSnpw" displayName="태양광" formatter="{numFmt}">'
			+ '						<fill>'
			+ '							<SolidColor color="#FFCA7C" />'
			+ '						</fill>'
			+ '						<showDataEffect>'
			+ '							<SeriesInterpolate />'
			+ '						</showDataEffect>'
			+ '					</Column2DSeries>'
			+ '					<Column2DSeries color="#222222" font-weight="bold" yField="prdctnWdpw" displayName="풍력" formatter="{numFmt}">'
			+ '						<fill>'
			+ '							<SolidColor color="#9CA5F3" />'
			+ '						</fill>'
			+ '						<showDataEffect>'
			+ '							<SeriesInterpolate />'
			+ '						</showDataEffect>'
			+ '					</Column2DSeries>'
			+ '					<Column2DSeries color="#222222" font-weight="bold" yField="prdctnWtht" displayName="수열" formatter="{numFmt}">'
			+ '						<fill>'
			+ '							<SolidColor color="#68E1CE" />'
			+ '						</fill>'
			+ '						<showDataEffect>'
			+ '							<SeriesInterpolate />'
			+ '						</showDataEffect>'
			+ '					</Column2DSeries>'
			+ '				</series>'
			+ '			</Column2DSet>'
			+ '		</series>'
			+ '	</Column2DChart>'
			+ '</rMateChart>';
	} else {
		var elcpwstn = {
			"prdctnLgwtpw" : "대수력",
			"prdctnSmlhp" : "소수력",
			"prdctnTdpw" : "조력",
			"prdctnSnpw" : "태양광",
			"prdctnWdpw" : "풍력",
			"prdctnWtht" : "수열"
		};
		Object.keys(elcpwstn).forEach(source => {
			var obj = {};
			var temp = prdctnData.filter(obj => obj.elcpwstnClsNm == elcpwstn[source]);
			obj["basin"] = elcpwstn[source];
			obj["data"] = (temp[temp.findIndex(obj => Number(obj.inqireDe) == dashYear && obj.elcpwstnClsNm.endsWith(elcpwstn[source]))] || 0).inqireIemVu;
			// 유역, 대수력, 소수력, 조력, 태양광, 풍력, 수열
			chartList.push(obj);
		});

		var maxData = chartList.reduce((max, obj) => Math.max(max, obj.data ?? 0), 0);
		var chartUnit = Math.max(scwin.initData.chart.prdctnUnit, Math.pow(10, String(maxData.toFixed(0)).length - 2));
		var interval = Math.ceil((maxData / scwin.initData.chart.prdctnIntervalCount) / scwin.initData.chart.prdctnUnit) * scwin.initData.chart.prdctnUnit;

		var layoutStr = '<rMateChart backgroundColor="" cornerRadius="12">'
			+ '	<Options>'
			+ '		<Legend position="center" vAlign="top" hAlign="right" verticalGap="2" fontWeight="bold" border="0" background="transparent" />'
			+ '	</Options>'
			+ '	<NumberFormatter id="numFmt" useThousandsSeparator="true"/>'
			+ '	<Column2DChart showDataTips="true" columnWidthRatio="0.45" dataTipDisplayMode="axis">'
			+ '		<horizontalAxis>'
			+ '			<CategoryAxis id="hAxis" categoryField="basin" />'
			+ '		</horizontalAxis>'
			+ '		<horizontalAxisRenderers>'
			+ '			<Axis2DRenderer axis="{hAxis}" textAlign="right" canDropLabels="false" />'
			+ '		</horizontalAxisRenderers>'
			+ '		<verticalAxis>'
			+ '			<LinearAxis id="vAxis" interval="' + interval + '" formatter="{numFmt}" title="MWh"/>'
			+ '		</verticalAxis>'
			+ '		<verticalAxisRenderers>'
			+ '			<Axis2DRenderer axis="{vAxis}" visible="true" placement="left" verticalAxisTitleAlignment="vertical" titleGap="0" canDropLabels="false" showLine="false" />'
			+ '		</verticalAxisRenderers>'
			+ '		<series>'
			+ '			<Column2DSeries color="#222222" font-weight="bold" yField="data" displayName="생산현황">'
			+ '				<fill>'
			+ '					<SolidColor color="#7DD2FF" />'
			+ '				</fill>'
			+ '				<showDataEffect>'
			+ '					<SeriesInterpolate />'
			+ '				</showDataEffect>'
			+ '			</Column2DSeries>'
			+ '		</series>'
			+ '	</Column2DChart>'
			+ '</rMateChart>';
	}
	document.getElementById(id).setLayout(layoutStr);
	document.getElementById(id).setData(chartList);
};

