				"cnstnItkpl" : (temp[temp.findIndex(obj => Number(obj.inqireDe) == dashYear && obj.elcpwstnClsNm.endsWith("취수장"))] || 0).inqireIemVu,
				"cnstnEtc" : (temp[temp.findIndex(obj => Number(obj.inqireDe) == dashYear && obj.elcpwstnClsNm.endsWith("기타"))] || 0).inqireIemVu
			});
