		var interval = Math.ceil((maxData / scwin.initData.chart.cnstnIntervalCount) / scwin.initData.chart.cnstnUnit) * scwin.initData.chart.cnstnUnit;
		var layoutStr = '<rMateChart backgroundColor="" cornerRadius="12">'
