			+ '						</showDataEffect>'
			+ '					</Column2DSeries>'
			+ '					<Column2DSeries color="#222222" font-weight="bold" yField="cnstnEtc" displayName="기타" formatter="{numFmt}">'
			+ '						<fill>'
			+ '							<SolidColor color="#FFCA7C" />'
			+ '						</fill>'
			+ '						<showDataEffect>'
			+ '							<SeriesInterpolate />'
			+ '						</showDataEffect>'
			+ '					</Column2DSeries>'
			+ '				</series>'
			+ '			</Column2DSet>'
			+ '		</series>'
			+ '	</Column2DChart>'
			+ '</rMateChart>';
	} else {
		var elcpwstn = {
			"cnstnFltplt" : "정수장",
			"cnstnPrnplc" : "가압장",
			"cnstnItkpl" : "취수장",
			"cnstnEtc" : "기타"
		};
		Object.keys(elcpwstn).forEach(source => {
			var obj = {};
			var temp = cnstnData.filter(obj => obj.elcpwstnClsNm == elcpwstn[source]);
			obj["basin"] = elcpwstn[source];
			obj["data"] = (temp[temp.findIndex(obj => Number(obj.inqireDe) == dashYear && obj.elcpwstnClsNm.endsWith(elcpwstn[source]))] || 0).inqireIemVu;
			// 유역, 정수장, 가압장, 취수장, 기타
			chartList.push(obj);
		});

		var maxData = chartList.reduce((max, obj) => Math.max(max, obj.data ?? 0), 0);
		var chartUnit = Math.max(scwin.initData.chart.prdctnUnit, Math.pow(10, String(maxData.toFixed(0)).length - 2));
		var interval = Math.ceil((maxData / scwin.initData.chart.prdctnIntervalCount) / scwin.initData.chart.prdctnUnit) * scwin.initData.chart.prdctnUnit;

		var layoutStr = '<rMateChart backgroundColor="" cornerRadius="12">'
			+ '	<Options>'
			+ '		<Legend position="center" vAlign="top" hAlign="right" verticalGap="2" fontWeight="bold" border="0" background="transparent" />'
			+ '	</Options>'
			+ '	<NumberFormatter id="numFmt" useThousandsSeparator="true"/>'
			+ '	<Column2DChart showDataTips="true" columnWidthRatio="0.45" dataTipDisplayMode="axis">'
			+ '		<horizontalAxis>'
			+ '			<CategoryAxis id="hAxis" categoryField="basin" />'
			+ '		</horizontalAxis>'
			+ '		<horizontalAxisRenderers>'
			+ '			<Axis2DRenderer axis="{hAxis}" textAlign="right" canDropLabels="false" />'
			+ '		</horizontalAxisRenderers>'
			+ '		<verticalAxis>'
			+ '			<LinearAxis id="vAxis" interval="' + interval + '" formatter="{numFmt}" title="MWh" />'
			+ '		</verticalAxis>'
			+ '		<verticalAxisRenderers>'
			+ '			<Axis2DRenderer axis="{vAxis}" visible="true" placement="left" verticalAxisTitleAlignment="vertical" titleGap="0" canDropLabels="false" showLine="false" />'
			+ '		</verticalAxisRenderers>'
			+ '		<series>'
			+ '			<Column2DSeries color="#222222" font-weight="bold" yField="data" displayName="소비현황">'
			+ '				<fill>'
			+ '					<SolidColor color="#7DD2FF" />'
			+ '				</fill>'
			+ '				<showDataEffect>'
			+ '					<SeriesInterpolate />'
			+ '				</showDataEffect>'
			+ '			</Column2DSeries>'
			+ '		</series>'
			+ '	</Column2DChart>'
			+ '</rMateChart>';
	}
	document.getElementById(id).setLayout(layoutStr);
	document.getElementById(id).setData(chartList);
};

/**
 * 전력에너지 탄소중립현황 데이터를 조회한다.
 */
scwin.searchCbnNtrltData = function() {
	var nowYear = utilLib.getCurrentDate("yyyy");
	var dashYear = dmaDashYear.getJSON();
	var selectedYear = String(dashYear.dashYearSelected);
	if (selectedYear == nowYear) {
		var endDt = utilLib.addMonth(utilLib.getCurrentDate("yyyyMM"), -2);
		var strtDt = endDt.substr(0, 4) + "01";
	} else {
		var strtDt = selectedYear + "01";
		var endDt = selectedYear + "12";
	}
	var dashBasin = dmaDashBasin.getJSON();
	var basin = dashBasin.dashBasinSelected;

	// info 날짜 설정_240131
	spnMainMapYearLabel.setLabel(endDt.substr(0, 4));
	spnMainMapMonthLabel.setLabel(endDt.substr(4, 2));

	basin = scwin.initData.dashBasinCode[scwin.initData.dashBasinValue[basin]] || "ALL";

	var queryString = `?strtDt=${strtDt}`;
	queryString += `&endDt=${endDt}`;
	queryString += `&ecsBasinDivCd=${basin}`;

	var option = {
		action : "ec/pc/retrieve-cbn-ntrlt.do" +
			queryString,
		method : "get",
		resData : dltCbnNtrltData,
		success : "scwin.searchCbnNtrltDataCallBack",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 전력에너지 탄소중립현황 데이터 조회 콜백
 */
