	var dsqtyData = (cbnNtrltData.find(obj => obj.inqireDe == dashYear && obj.iemDivId == "dsqtySum") || 0).inqireIemVu;
	var rqtyPer = Math.abs(Number(rqtyData.replaceAll(",", ""))) / (Math.abs(Number(rqtyData.replaceAll(",", ""))) + parseFloat(dsqtyData.replaceAll(",", "")));
	//var cbnNtrltComp = $p.getComponentById(document.querySelector("#" + $p.getFrameId() + " .dash-cbn-ntrlt-tree .dash-cbn-ntrlt-tree").id);
