	var selecotr = ".dash-con-box-pc .dash-box-con > .dash-box-con-cbn-ntrlt .main-cbn-ntrlt-scale > .main-cbn-ntrlt-data-box.main-cbn-ntrlt-data-box-";
	$p.getComponentById(document.querySelector(selecotr + "rqty > span.main-cbn-ntrlt-data-box-data").id).setLabel(ecsLib.dsplFrmt(rqtyData, 2));
