			sign = ">";
		}
		spnMainChartCbnNtrltTitleData.setLabel(sign);
		//grpMainCbnNtrltScaleSvg.setMainCbnNtrltData(acmtrtData);
		//$p.getComponentById(document.querySelector(selecotr + "rqty > span.main-cbn-ntrlt-data-box-data").id).setLabel(ecsLib.dsplFrmt(rqtyData));
		//$p.getComponentById(document.querySelector(selecotr + "dsqty > span.main-cbn-ntrlt-data-box-data").id).setLabel(ecsLib.dsplFrmt(dsqtyData));

		for (var key of Object.keys(styles)) {
			if (key != "rotate") {
				var transformStyle = `rotate(${styles.rotate}deg) translateY(${styles[key].translateY}%) translateX(${styles[key].translateX}%)`;
				transformStyle += styles[key]["scale"] ? ` scale(${styles[key]["scale"]})` : "";
				styles[key]["emt"].style.transform = transformStyle;
				styles[key]["emt"].style.transition = "all ease 2s 0.15s";
			}
		}
	}, existStyleTime || 500);
	/*
