	$p.getComponentById(document.querySelector(selecotr + "factory > .dash-cbn-ntrlt-factory-data-box.dash-cbn-ntrlt-factory-data-box-dsqty > span.dash-cbn-ntrlt-factory-data-box-data").id).setLabel(ecsLib.dsplFrmt(dsqtyData));
	// 우측 물방울 탄소중립율 라벨  값 설정
	//var acmtrtData = (cbnNtrltData.find(obj => obj.inqireDe == "fyer" && obj.iemDivId == "acmtrt") || 0).inqireIemVu;
	var acmtrtData = (cbnNtrltData.find(obj => obj.inqireDe == dashYear && obj.iemDivId == "acmtrt") || 0).inqireIemVu;
